+/**
+ * Webhook notification adapter.
+ *
+ * Implements NotificationAdapter for the 'webhook' channel.
+ * Features:
+ * - URL validation for webhook endpoints
+ * - JSON payload formatting
+ * - Pluggable transport layer (inject real HTTP client for production)
+ *
+ * Architecture constraint: All adapters must implement NotificationAdapter
+ * and be registered with NotificationService via registerAdapter().
+ */
+
+import type {
+  NotificationAdapter,
+  NotificationPayload,
+  NotificationResult,
+} from '../models/notification.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookConfig {
+  /** Default timeout in milliseconds */
+  timeoutMs?: number;
+  /** Optional secret for signing payloads */
+  secret?: string;
+  /** Optional custom headers to include in every request */
+  defaultHeaders?: Record<string, string>;
+}
+
+/**
+ * The JSON body sent to webhook endpoints.
+ */
+export interface WebhookRequestPayload {
+  url: string;
+  method: 'POST';
+  headers: Record<string, string>;
+  body: string;
+}
+
+/**
+ * Transport interface for sending webhook HTTP requests.
+ * Implement this with your HTTP client (fetch, axios, etc.)
+ */
+export interface WebhookTransport {
+  send(request: WebhookRequestPayload): Promise<{ statusCode: number }>;
+}
+
+/**
+ * In-memory transport that captures sent webhooks. Useful for testing and development.
+ */
+export class InMemoryWebhookTransport implements WebhookTransport {
+  private sent: WebhookRequestPayload[] = [];
+
+  async send(request: WebhookRequestPayload): Promise<{ statusCode: number }> {
+    this.sent.push(request);
+    return { statusCode: 200 };
+  }
+
+  getSentRequests(): WebhookRequestPayload[] {
+    return [...this.sent];
+  }
+
+  clear(): void {
+    this.sent = [];
+  }
+}
+
+const URL_REGEX = /^https?:\/\/[^\s/$.?#].[^\s]*$/;
+
+/**
+ * Validate that a string looks like an HTTP(S) URL.
+ */
+export function isValidWebhookUrl(url: string): boolean {
+  if (!url || url.length > 2048) return false;
+  return URL_REGEX.test(url);
+}
+
+export class WebhookNotificationAdapter implements NotificationAdapter {
+  readonly channel = 'webhook' as const;
+  private logger = new Logger('WebhookAdapter');
+  private transport: WebhookTransport;
+  private config: WebhookConfig;
+
+  constructor(config?: WebhookConfig, transport?: WebhookTransport) {
+    this.config = config ?? {};
+    this.transport = transport ?? new InMemoryWebhookTransport();
+  }
+
+  /**
+   * Validate and resolve the webhook URL.
+   * Returns the validated URL or throws if invalid.
+   */
+  resolveRecipient(recipient: string): string {
+    const trimmed = recipient.trim();
+
+    if (!trimmed) {
+      throw new Error('Webhook URL cannot be empty');
+    }
+
+    if (trimmed.length > 2048) {
+      throw new Error('Webhook URL exceeds maximum length of 2048');
+    }
+
+    if (!isValidWebhookUrl(trimmed)) {
+      throw new Error(`Invalid webhook URL: ${trimmed}`);
+    }
+
+    return trimmed;
+  }
+
+  /**
+   * Format a notification payload into a webhook HTTP request.
+   */
+  formatRequest(payload: NotificationPayload, url: string): WebhookRequestPayload {
+    const headers: Record<string, string> = {
+      'Content-Type': 'application/json',
+      ...this.config.defaultHeaders,
+    };
+
+    if (this.config.secret) {
+      headers['X-Webhook-Secret'] = this.config.secret;
+    }
+
+    const body = JSON.stringify({
+      id: payload.id,
+      type: payload.type,
+      channel: payload.channel,
+      recipient: url,
+      subject: payload.subject,
+      body: payload.body,
+      metadata: payload.metadata ?? {},
+      createdAt: payload.createdAt.toISOString(),
+    });
+
+    return {
+      url,
+      method: 'POST',
+      headers,
+      body,
+    };
+  }
+
+  /**
+   * Send a notification via webhook.
+   *
+   * 1. Validates the recipient URL
+   * 2. Formats the JSON payload
+   * 3. Sends via the configured transport
+   */
+  async send(payload: NotificationPayload): Promise<NotificationResult> {
+    try {
+      const resolvedUrl = this.resolveRecipient(payload.recipient);
+
+      const request = this.formatRequest(payload, resolvedUrl);
+
+      this.logger.info(
+        `Sending webhook to ${resolvedUrl}: "${payload.subject}"`,
+      );
+
+      const response = await this.transport.send(request);
+
+      if (response.statusCode >= 200 && response.statusCode < 300) {
+        this.logger.info(`Webhook delivered to ${resolvedUrl}`);
+
+        return {
+          notificationId: payload.id,
+          channel: 'webhook',
+          success: true,
+          deliveredAt: new Date(),
+        };
+      }
+
+      const errorMsg = `Webhook returned status ${response.statusCode}`;
+      this.logger.error(`Failed webhook for ${payload.id}: ${errorMsg}`);
+
+      return {
+        notificationId: payload.id,
+        channel: 'webhook',
+        success: false,
+        error: errorMsg,
+        deliveredAt: new Date(),
+      };
+    } catch (error) {
+      const message = error instanceof Error ? error.message : String(error);
+      this.logger.error(`Failed to send webhook for ${payload.id}: ${message}`);
+
+      return {
+        notificationId: payload.id,
+        channel: 'webhook',
+        success: false,
+        error: message,
+        deliveredAt: new Date(),
+      };
+    }
+  }
+
+  /**
+   * Get all requests sent through this adapter (only works with InMemoryWebhookTransport).
+   */
+  getSentRequests(): WebhookRequestPayload[] {
+    if (this.transport instanceof InMemoryWebhookTransport) {
+      return this.transport.getSentRequests();
+    }
+    return [];
+  }
+
+  /**
+   * Clear sent requests (only works with InMemoryWebhookTransport).
+   */
+  clearSentRequests(): void {
+    if (this.transport instanceof InMemoryWebhookTransport) {
+      this.transport.clear();
+    }
+  }
+
+  /**
+   * Get the underlying transport (useful for testing).
+   */
+  getTransport(): WebhookTransport {
+    return this.transport;
+  }
+}

