  });

  it('should capture sent requests', async () => {
    const request: WebhookRequestPayload = {
      url: 'https://hooks.example.com/notify',
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: '{"test":true}',
    };

    const result = await transport.send(request);
    expect(result.statusCode).toBe(200);
    expect(transport.getSentRequests()).toHaveLength(1);
    expect(transport.getSentRequests()[0]?.url).toBe('https://hooks.example.com/notify');
  });

  it('should clear sent requests', async () => {
    const request: WebhookRequestPayload = {
      url: 'https://hooks.example.com/notify',
      method: 'POST',
      headers: {},
      body: '{}',
    };

    await transport.send(request);
    transport.clear();
    expect(transport.getSentRequests()).toHaveLength(0);
  });
});

describe('WebhookNotificationAdapter', () => {
  let adapter: WebhookNotificationAdapter;
  let transport: InMemoryWebhookTransport;

  beforeEach(() => {
    transport = new InMemoryWebhookTransport();
    adapter = new WebhookNotificationAdapter(defaultConfig, transport);
  });

  describe('channel', () => {
    it('should report webhook channel', () => {
      expect(adapter.channel).toBe('webhook');
    });
  });

  describe('resolveRecipient', () => {
    it('should accept and trim valid URLs', () => {
      expect(adapter.resolveRecipient('  https://hooks.example.com/notify  ')).toBe(
        'https://hooks.example.com/notify',
      );
    });

    it('should throw for empty URL', () => {
      expect(() => adapter.resolveRecipient('')).toThrow('cannot be empty');
      expect(() => adapter.resolveRecipient('   ')).toThrow('cannot be empty');
    });

    it('should throw for invalid URL', () => {
      expect(() => adapter.resolveRecipient('not-a-url')).toThrow('Invalid webhook URL');
    });

    it('should throw for overly long URL', () => {
      const longUrl = 'https://example.com/' + 'a'.repeat(2048);
      expect(() => adapter.resolveRecipient(longUrl)).toThrow('exceeds maximum length');
    });
  });

  describe('formatRequest', () => {
    it('should format a notification as a JSON POST request', () => {
      const payload = makePayload();
      const request = adapter.formatRequest(payload, 'https://hooks.example.com/notify');

      expect(request.url).toBe('https://hooks.example.com/notify');
      expect(request.method).toBe('POST');
      expect(request.headers['Content-Type']).toBe('application/json');

      const body = JSON.parse(request.body);
      expect(body.id).toBe('notif-0001');
      expect(body.type).toBe('order_confirmation');
      expect(body.subject).toBe('Order Confirmation: order-1');
      expect(body.body).toContain('Widget x2');
      expect(body.createdAt).toBe('2026-01-01T00:00:00.000Z');
    });

    it('should include secret header when configured', () => {
      const secretAdapter = new WebhookNotificationAdapter(
        { secret: 'my-secret-key' },
        transport,
      );
      const payload = makePayload();
      const request = secretAdapter.formatRequest(payload, 'https://hooks.example.com/notify');

      expect(request.headers['X-Webhook-Secret']).toBe('my-secret-key');
    });

    it('should include custom default headers', () => {
      const headerAdapter = new WebhookNotificationAdapter(
        { defaultHeaders: { 'X-Custom': 'value' } },
        transport,
      );
      const payload = makePayload();
      const request = headerAdapter.formatRequest(payload, 'https://hooks.example.com/notify');

      expect(request.headers['X-Custom']).toBe('value');
      expect(request.headers['Content-Type']).toBe('application/json');
    });

    it('should include metadata in body when present', () => {
      const payload = makePayload({ metadata: { orderId: 'order-42' } });
      const request = adapter.formatRequest(payload, 'https://hooks.example.com/notify');

      const body = JSON.parse(request.body);
      expect(body.metadata.orderId).toBe('order-42');
    });

    it('should default metadata to empty object when absent', () => {
      const payload = makePayload();
      const request = adapter.formatRequest(payload, 'https://hooks.example.com/notify');

      const body = JSON.parse(request.body);
      expect(body.metadata).toEqual({});
    });
  });

  describe('send', () => {
    it('should send a valid notification and return success', async () => {
      const payload = makePayload();
      const result = await adapter.send(payload);

      expect(result.success).toBe(true);
      expect(result.notificationId).toBe('notif-0001');
      expect(result.channel).toBe('webhook');
      expect(result.deliveredAt).toBeInstanceOf(Date);

      const sent = transport.getSentRequests();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
      expect(sent[0]?.method).toBe('POST');
    });

    it('should trim recipient URL before sending', async () => {
      const payload = makePayload({ recipient: '  https://hooks.example.com/notify  ' });
      await adapter.send(payload);

      const sent = transport.getSentRequests();
      expect(sent[0]?.url).toBe('https://hooks.example.com/notify');
    });

    it('should return failure for invalid URL', async () => {
      const payload = makePayload({ recipient: 'not-a-url' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid webhook URL');
      expect(transport.getSentRequests()).toHaveLength(0);
    });

    it('should return failure for empty URL', async () => {
      const payload = makePayload({ recipient: '' });
      const result = await adapter.send(payload);

      expect(result.success).toBe(false);
      expect(result.error).toContain('cannot be empty');
    });

    it('should return failure when transport throws', async () => {
      const failingTransport: WebhookTransport = {
        send: async () => {
          throw new Error('Connection refused');
        },
      };
      const failAdapter = new WebhookNotificationAdapter(defaultConfig, failingTransport);

      const result = await failAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toBe('Connection refused');
    });

    it('should return failure for non-2xx status codes', async () => {
      const badTransport: WebhookTransport = {
        send: async () => ({ statusCode: 500 }),
      };
      const badAdapter = new WebhookNotificationAdapter(defaultConfig, badTransport);

      const result = await badAdapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.error).toContain('status 500');
    });

    it('should succeed for any 2xx status code', async () => {
      const accepted: WebhookTransport = {
        send: async () => ({ statusCode: 202 }),
      };
      const acceptedAdapter = new WebhookNotificationAdapter(defaultConfig, accepted);

      const result = await acceptedAdapter.send(makePayload());
      expect(result.success).toBe(true);
    });
  });

  describe('getSentRequests / clearSentRequests', () => {
    it('should return sent requests from in-memory transport', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentRequests()).toHaveLength(1);
    });

    it('should clear sent requests', async () => {
      await adapter.send(makePayload());
      adapter.clearSentRequests();
      expect(adapter.getSentRequests()).toHaveLength(0);
    });

    it('should return empty array when using non-InMemory transport', () => {
      const customTransport: WebhookTransport = {
        send: async () => ({ statusCode: 200 }),
      };
      const customAdapter = new WebhookNotificationAdapter(defaultConfig, customTransport);
      expect(customAdapter.getSentRequests()).toEqual([]);
    });
  });

  describe('getTransport', () => {
    it('should return the underlying transport', () => {
      expect(adapter.getTransport()).toBe(transport);
    });
  });
});

